SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_dep_m_creditor ON sc_dep_m_creditor CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_dep_m_creditor() RETURNS trigger AS $BODY$
declare
  ls_depno sc_dep_m_creditor.deposit_account_no%type;
  ls_main_br char(1);
BEGIN
--return ;
--Niorn 2024-07-23 สะสมทรัยพ์ ดอกเบี้ย และต้น โอนไปธนาคารเท่านั้น
-- 2:โอนเข้าออมทรัพย์ , 0:เข้าธนาคาร , 9:โอนเข้าตัวเอง
if pka.isCoop('POT')= '1'  and ( NEW.deposit_type_code = '32' or NEW.deposit_type_code = '56' ) then
	NEW.method_int_month := '0';
end if;

--Niorn 2021-02-04 Krabi เปิดแล้วตอนปิดบัญชีมัน Mutate ปิดไปก่อน 
--  if :old.close_status = '0' and :new.close_status = 'C' then    
--    
--    -- ปิดบัญชี เอาไปไว้ทำรายการรับดอกเบี้ยหรือไม่
--    begin -- บัญชีรับดอกเบี้ย
--      select deposit_account_no  into ls_depno
--      from sc_dep_m_creditor
--      where 1=1
--      and deposit_balance > 0 
--      and deposit_account_no_other = :new.deposit_account_no 
--      and(rownum = 1) ;
--      if ls_depno <> ' '  then
--        spa_dberror('บัญชีเงินฝาก('||trim(:new.deposit_account_no)||') เป็นบัญชีดอกเบี้ยรับของบัญชี('||trim(ls_depno)||') ไม่สามารถปิดบัญชีได้');
--      end if;
--    end  ;
--  end if;
  --Niorn 2023-12-23 TGE Default method_int_month = '0'
  --Niorn 2024-06-26 POT Default method_int_month = '2'
  if coalesce(NEW.method_int_month::text, '') = '' then NEW.method_int_month := '2';end if;

  if coalesce(NEW.deposit_balance::text, '') = '' then NEW.deposit_balance := 0;end if;
  if coalesce(NEW.withdrawable_amount::text, '') = '' then NEW.withdrawable_amount := NEW.deposit_balance;end if;
  if coalesce(NEW.cheque_pending_amount::text, '') = '' then NEW.cheque_pending_amount := 0;end if;
  if coalesce(NEW.loan_holding_amount::text, '') = '' then NEW.loan_holding_amount := 0;end if;
  if coalesce(NEW.deposit_standsecurity_amount::text, '') = '' then NEW.deposit_standsecurity_amount := 0;end if;
  if coalesce(NEW.sequester_status::text, '') = '' then NEW.sequester_status := '0';end if;
  if coalesce(NEW.withdraw_count::text, '') = '' then NEW.withdraw_count := 0;end if;
  if coalesce(NEW.accumulate_interest::text, '') = '' then NEW.accumulate_interest := 0;end if;
  if coalesce(NEW.BEGINg_balance::text, '') = '' then NEW.BEGINg_balance := 0;end if;
  if coalesce(NEW.present_account_year::text, '') = '' then NEW.present_account_year := 0;end if;
  if coalesce(NEW.special_rule_status::text, '') = '' then NEW.special_rule_status :='0';end if;
  if coalesce(NEW.monthly_int_status::text, '') = '' then NEW.monthly_int_status :='0';end if;
  if coalesce(NEW.monthly_deposit_status::text, '') = '' then NEW.monthly_deposit_status :='0';end if;
  if coalesce(NEW.monthly_deposit_amount::text, '') = '' then NEW.monthly_deposit_amount := 0;end if;
  if coalesce(NEW.tax_status::text, '') = '' then NEW.tax_status :='0';end if;
  if coalesce(NEW.moneytype_deposit_status::text, '') = '' then NEW.moneytype_deposit_status :='0';end if;
  if coalesce(NEW.last_page::text, '') = '' then NEW.last_page := 0;end if;
  if coalesce(NEW.card_last_line::text, '') = '' then NEW.card_last_line := 0;end if;
  if coalesce(NEW.int_rate_status::text, '') = '' then NEW.int_rate_status :='0';end if;
  if coalesce(NEW.int_rate::text, '') = '' then NEW.int_rate :=0;end if;
  if coalesce(NEW.close_status::text, '') = '' then NEW.close_status :='0';end if;
  if coalesce(NEW.member_status::text, '') = '' then NEW.member_status :='1';end if;
  if coalesce(NEW.conclude_fixed::text, '') = '' then NEW.conclude_fixed :='0';end if;
  if coalesce(NEW.mlr_status::text, '') = '' then NEW.mlr_status :='0';end if;
  if coalesce(NEW.not_int_comound_status::text, '') = '' then NEW.not_int_comound_status :='0';end if;
  if coalesce(NEW.accu_int_holding::text, '') = '' then NEW.accu_int_holding :=0;end if;
  if coalesce(NEW.printed_seq_no::text, '') = '' then NEW.printed_seq_no :=0;end if;
  if coalesce(NEW.movement_times::text, '') = '' then NEW.movement_times :=0;end if;
  if coalesce(trim(both NEW.officer_id)::text, '') = '' then NEW.officer_id := current_setting('app.login_id', true);end if;
  if coalesce(trim(both NEW.branch_id)::text, '') = '' then NEW.branch_id := current_setting('app.login_br', true);end if;
  if coalesce(trim(both NEW.atm_status)::text, '') = '' then NEW.atm_status := '0';end if;

  --if :new.last_compound_date is null then :new.last_compound_date :=
  --รองรับ การเอาข้อมูลไปบริการสมาชิกนอกสถานที่
  if current_setting('app.login_br', true) = '01' then
    --main
    NEW.last_access_time_main := to_char(statement_timestamp(),'YYYY-MM-DD HH24:MI:SS.MS');
  else
    --onsite
    NEW.last_access_time_onsite := to_char(statement_timestamp(),'YYYY-MM-DD HH24:MI:SS.MS');
  end if;

  -- บังคับเพื่ออัพเดท
  NEW.last_access_time  := to_char(statement_timestamp(),'YYYY-MM-DD HH24:MI:SS.MS');

  -- เฉพาะตอนเปิดบัญชีครั้งแรก ซึ่ง ห้ามเป็น NULL
  if length(trim(both NEW.last_access_time_main)) > 0 then null;
  else
    NEW.last_access_time_main := to_char(statement_timestamp(),'YYYY-MM-DD HH24:MI:SS.MS');
  end if;
  if length(trim(both NEW.last_access_time_onsite)) > 0 then null;
  else
    NEW.last_access_time_onsite := to_char(statement_timestamp(),'YYYY-MM-DD HH24:MI:SS.MS');
  end if;

    --แก้ไข ฝากรายเดือน
  if (OLD.MONTHLY_DEPOSIT_AMOUNT IS NOT NULL AND OLD.MONTHLY_DEPOSIT_AMOUNT::text <> '' AND ( NEW.monthly_deposit_status <> OLD.monthly_deposit_status
           or NEW.MONTHLY_DEPOSIT_AMOUNT <> OLD.MONTHLY_DEPOSIT_AMOUNT ))  then 
    --insert  sc_mem_edit_salary
   INSERT INTO SC_DEP_EDIT_MONTHLY_DEPOSIT( DEPOSIT_ACCOUNT_NO,           entry_date,             entry_id,   
           operate_date,                
           PRE_MONTHLY_DEPOSIT_AMOUNT,        
           MONTHLY_DEPOSIT_AMOUNT    ,         entry_br ,
           pre_monthly_deposit_status, 
           monthly_deposit_status )  
  VALUES ( NEW.deposit_account_no,              statement_timestamp(),               current_setting('app.login_id', true),   
           TO_DATE( statement_timestamp() ),              
           OLD.MONTHLY_DEPOSIT_AMOUNT,        
           NEW.MONTHLY_DEPOSIT_AMOUNT ,    current_setting('app.login_br', true)   ,   
           OLD.monthly_deposit_status,
           NEW.monthly_deposit_status) 
;
  end if;

    --บัญชีครบดิว
  if ( (OLD.deposit_account_no IS NOT NULL AND OLD.deposit_account_no::text <> '') and NEW.fixed_due_to_dep_no <> OLD.fixed_due_to_dep_no ) or ( coalesce(OLD.fixed_due_to_dep_no::text, '') = '' and (NEW.fixed_due_to_dep_no IS NOT NULL AND NEW.fixed_due_to_dep_no::text <> '') ) then 
    --insert  SC_DEP_EDIT_FIXED_DUE_DEP
   INSERT INTO SC_DEP_EDIT_FIXED_DUE_DEP( DEPOSIT_ACCOUNT_NO,           entry_date,             entry_id,   
           operate_date,                
           PRE_FIXED_DUE_DEP,       
           FIXED_DUE_DEP,                 entry_br )  
  VALUES ( NEW.deposit_account_no,            statement_timestamp(),               current_setting('app.login_id', true),   
           TO_DATE( statement_timestamp() ),              
           OLD.fixed_due_to_dep_no,        
           NEW.fixed_due_to_dep_no,      current_setting('app.login_br', true)        
           ) 
;
  end if;

  if OLD.close_status = '0' and NEW.close_status = 'C' then 
    NEW.close_id := current_setting('app.login_id', true);
    NEW.close_branch_id := current_setting('app.login_br', true);
  end if;

  --ไฟฟ้าประเภท 13 บังคับเสียภาษี และ รับรายเดือน
  if NEW.deposit_type_code = '13' and pka.isCoop('KFN' ) =  '1' then
    NEW.monthly_int_status := '1';
  end if;


    --แก้ไขการรับดอกเบี้ยรายเดือน  
  if (OLD.deposit_account_no IS NOT NULL AND OLD.deposit_account_no::text <> '' AND ( NEW.monthly_int_status <> OLD.monthly_int_status
           or NEW.method_int_month <> OLD.method_int_month 
           or NEW.deposit_account_no_other <> OLD.deposit_account_no_other 
           or NEW.account_bank <> OLD.account_bank            
           ))  then 
    --insert  SC_DEP_EDIT_MONTHLY_INT
   INSERT INTO SC_DEP_EDIT_MONTHLY_INT( DEPOSIT_ACCOUNT_NO,              entry_date,             entry_id,                
           entry_br ,                         operate_date,                
           pre_monthly_int_status,          monthly_int_status    ,         
           pre_method_int_month,            method_int_month,
           pre_deposit_account_no_other,    deposit_account_no_other ,
           pre_account_bank,                account_bank           
           )  
  VALUES ( NEW.deposit_account_no,               statement_timestamp(),               current_setting('app.login_id', true),   
           current_setting('app.login_br', true)   ,             TO_DATE( statement_timestamp() ),              
           OLD.monthly_int_status,             NEW.monthly_int_status ,       
           OLD.method_int_month,               NEW.method_int_month,
           OLD.deposit_account_no_other,       NEW.deposit_account_no_other,
           OLD.account_bank,                   NEW.account_bank
           ) 
;
  end if;

    --Niorn 20200927 validate int_rate_status กับ int_rate
  if NEW.int_rate_status = '1' and NEW.int_rate =  0 and NEW.close_status = '0' then
    CALL spa_dberror('T165:ไม่รองรับการใช้อัตราดอกเบี้ยพิเศษ 0%');
  end if;

  --Niorn 2021-04-01 krabi เงินฝาก ชคส ไม่นำมาคิดภาระรายเดือน
  if coalesce(NEW.krabi_status::text, '') = '' then NEW.krabi_status :='0';end if;

  --1 : ไม่ทำธุรกรรมบนโมบาย
  --if :new.join_status is null then :new.join_status :='0';end if;
  --Niorn 2023-05-17 TGE ออมทรัพย์พิเศษ default ไม่ทำธุรกรรมบนโมบาย 
  if pka.isCoop('TGE' ) =  '1' and coalesce(OLD.deposit_account_no::text, '') = '' and NEW.join_status = '0' then
    if NEW.deposit_type_code = '40' or NEW.deposit_type_code = '41' then
        NEW.join_status := '1';
    else
        NEW.join_status := '0';
    end if;
  else
    if coalesce(NEW.join_status::text, '') = '' then NEW.join_status :='0';end if;
  end if;

  --Niorn 2023-05-01 TGE บรรทัดที่เริ่มพิมพ์อย่างน้อยต้องเป็น 1
  if coalesce(NEW.last_line::text, '') = '' or NEW.last_line = 0 then NEW.last_line := 1;end if;


    --Niorn 2024-02-15 แก้ไข การอายัด
    if (OLD.deposit_standsecurity_amount IS NOT NULL AND OLD.deposit_standsecurity_amount::text <> '' AND ( NEW.SEQUESTER_STATUS <> OLD.SEQUESTER_STATUS
           or NEW.deposit_standsecurity_amount <> OLD.deposit_standsecurity_amount 
           or NEW.REMARK_SEQUES <> OLD.REMARK_SEQUES ))  then 
    --insert  SC_DEP_EDIT_SEQUESTER
   INSERT INTO SC_DEP_EDIT_SEQUESTER( DEPOSIT_ACCOUNT_NO,                entry_date,             entry_id,   
           entry_br ,                           operate_date,                
           PRE_SEQUESTER_STATUS,                SEQUESTER_STATUS    ,         
           PRE_SEQUESTER_AMOUNT,                SEQUESTER_AMOUNT    ,  
           PRE_REMARK_SEQUES,                   REMARK_SEQUES     )  
  VALUES ( NEW.deposit_account_no,             statement_timestamp(),                current_setting('app.login_id', true),   
           current_setting('app.login_br', true),              TO_DATE( statement_timestamp() ),              
           OLD.SEQUESTER_STATUS,               NEW.SEQUESTER_STATUS ,      
           OLD.deposit_standsecurity_amount,   NEW.deposit_standsecurity_amount , 
           OLD.REMARK_SEQUES,                  NEW.REMARK_SEQUES  ) 
;
  end if;

  --Niorn 2024-05-27 MWA แก้ไข ชื่อบัญชี วัตถุประสงค์  หมายเหคุ
  if (OLD.DEPOSIT_ACCOUNT_NO IS NOT NULL AND OLD.DEPOSIT_ACCOUNT_NO::text <> '' AND ( NEW.DEPOSIT_ACCOUNT_NAME <> OLD.DEPOSIT_ACCOUNT_NAME  
           or NEW.DEPOSIT_OBJECTIVE <> OLD.DEPOSIT_OBJECTIVE          
           or NEW.REMARK <> OLD.REMARK
           ))  then 
   --insert  SC_DEP_EDIT_DEPOSIT
   INSERT INTO SC_DEP_EDIT_DEPOSIT( DEPOSIT_ACCOUNT_NO,           entry_date,             entry_id,   
           operate_date,                
           PRE_DEPOSIT_ACCOUNT_NAME,        
           DEPOSIT_ACCOUNT_NAME    ,         
           PRE_DEPOSIT_OBJECTIVE, 
           DEPOSIT_OBJECTIVE,          
           PRE_REMARK, 
           REMARK           
           
           )  
  VALUES ( NEW.deposit_account_no,              statement_timestamp(),               current_setting('app.login_id', true),   
           TO_DATE( statement_timestamp() ),              
           OLD.DEPOSIT_ACCOUNT_NAME,        
           NEW.DEPOSIT_ACCOUNT_NAME ,    
           OLD.DEPOSIT_OBJECTIVE,
           NEW.DEPOSIT_OBJECTIVE,        
           OLD.REMARK,
           NEW.REMARK           
           
           
           ) 
;
  end if;
  --Niorn 2024-06-12 POT รับรายเดือน เข้าออมทรัพย์ ถ้าไม่เซตบัญชีรับโอนดอกเบี้ย ให้เข้าตัวเอง
  if NEW.method_int_month = '2' and  NEW.deposit_account_no_other = 'NEW' then 
    NEW.deposit_account_no_other := NEW.deposit_account_no;
  end if;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_dep_m_creditor() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_dep_m_creditor
	BEFORE INSERT OR UPDATE ON sc_dep_m_creditor FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_dep_m_creditor();

